import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';

export default function StudentProfile() {
  const { user, setUser } = useAuth();
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState({ type: '', text: '' });
  const [form, setForm] = useState({ name: '', phone: '', address: '', boardingPoint: '', parentPhone: '' });
  const [pwForm, setPwForm] = useState({ currentPassword: '', newPassword: '', confirmPassword: '' });
  const [pwSaving, setPwSaving] = useState(false);

  useEffect(() => {
    axios.get('/students/profile')
      .then(r => {
        setProfile(r.data);
        setForm({
          name: r.data.user?.name || '',
          phone: r.data.user?.phone || '',
          address: r.data.address || '',
          boardingPoint: r.data.boardingPoint || '',
          parentPhone: r.data.parentPhone || '',
        });
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const handleSave = async (e) => {
    e.preventDefault();
    setSaving(true);
    setMsg({ type: '', text: '' });
    try {
      // 1. Update basic user info
      const authRes = await axios.put('/auth/profile', { 
        name: form.name, 
        phone: form.phone 
      });

      // 2. Update student specific info
      const studentRes = await axios.put('/students/profile', {
        address: form.address,
        boardingPoint: form.boardingPoint,
        parentPhone: form.parentPhone
      });

      // Update local context
      const updatedUser = { ...user, ...authRes.data.user };
      localStorage.setItem('user', JSON.stringify(updatedUser));
      setUser(updatedUser);
      setProfile(studentRes.data.profile);

      setMsg({ type: 'success', text: 'Profile updated successfully.' });
    } catch (err) {
      setMsg({ type: 'error', text: err.response?.data?.message || 'Failed to update profile.' });
    } finally {
      setSaving(false);
    }
  };

  const handlePassword = async (e) => {
    e.preventDefault();
    if (pwForm.newPassword !== pwForm.confirmPassword) {
      setMsg({ type: 'error', text: 'New passwords do not match.' });
      return;
    }
    setPwSaving(true);
    setMsg({ type: '', text: '' });
    try {
      await axios.put('/auth/change-password', {
        currentPassword: pwForm.currentPassword,
        newPassword: pwForm.newPassword,
      });
      setPwForm({ currentPassword: '', newPassword: '', confirmPassword: '' });
      setMsg({ type: 'success', text: 'Password updated successfully.' });
    } catch (err) {
      setMsg({ type: 'error', text: err.response?.data?.message || 'Failed to change password.' });
    } finally {
      setPwSaving(false);
    }
  };

  if (loading) return <div className="loading-screen" style={{ height: 300 }}><div className="spinner" /><p className="text-muted">Loading profile...</p></div>;

  return (
    <div className="animate-fade">
      <div className="page-hero">
        <p className="page-hero-label">KEC Student Portal</p>
        <h2>My Profile</h2>
        <p className="page-hero-meta">View and manage your academic and transport information</p>
      </div>

      <div className="profile-header">
        <div className="profile-avatar-lg">{user?.name?.charAt(0).toUpperCase()}</div>
        <div className="profile-info">
          <h1>{user?.name}</h1>
          <p>{profile?.studentId} · {profile?.department} · Year {profile?.year}</p>
          <div className="profile-badges" style={{ marginTop: 8 }}>
            <span className="badge badge-student">Active Student</span>
            {profile?.route && <span className="badge badge-route">Route {profile.route.routeNumber}</span>}
            <span className="kec-badge">KEC Erode</span>
          </div>
        </div>
      </div>

      {msg.text && <div className={`alert alert-${msg.type === 'success' ? 'success' : 'error'}`}>{msg.text}</div>}

      <div className="profile-tab-grid">
        <div style={{ display: 'flex', flexDirection: 'column', gap: 20 }}>
          <div className="card">
            <div className="card-header">
              <h3 className="card-title"><span>🎓</span> Academic Info</h3>
              <span className="readonly-tag">Read only</span>
            </div>
            <div className="info-list">
              {[
                ['Student ID', profile?.studentId],
                ['Roll Number', profile?.rollNumber],
                ['Department', profile?.department],
                ['Year / Section', `Year ${profile?.year} · Section ${profile?.section || '—'}`],
                ['College Email', profile?.user?.email],
                ['Admission Date', profile?.admissionDate],
                ['Joining Month', profile?.joiningMonth],
              ].map(([k, v]) => (
                <div className="info-row" key={k}><span>{k}</span><strong>{v || '—'}</strong></div>
              ))}
            </div>
          </div>

          {profile?.route && (
            <div className="card">
              <div className="card-header">
                <h3 className="card-title"><span>🚌</span> Transport Details</h3>
                <span className="readonly-tag">Managed by Admin</span>
              </div>
              <div className="route-visual" style={{ marginBottom: 20 }}>
                <div className="route-stop"><span>Origin</span><strong>{profile.route.startPoint}</strong></div>
                <div className="route-line" />
                <div className="route-stop route-stop-mid"><span>My Point</span><strong>{profile.boardingPoint || '—'}</strong></div>
                <div className="route-line" />
                <div className="route-stop"><span>Campus</span><strong>KEC</strong></div>
              </div>
              <div className="info-list">
                <div className="info-row"><span>Route Number</span><strong>{profile.route.routeNumber}</strong></div>
                <div className="info-row"><span>Route Name</span><strong>{profile.route.routeName}</strong></div>
                <div className="info-row"><span>Monthly Fare</span><strong>₹{Number(profile.route.monthlyFee).toLocaleString('en-IN')}</strong></div>
                <div className="info-row"><span>Fee Plan</span><strong className="capitalize">{profile.feeType}</strong></div>
              </div>
            </div>
          )}
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: 20 }}>
          <div className="card">
            <div className="card-header">
              <h3 className="card-title"><span>✏️</span> Edit Profile</h3>
            </div>
            <form onSubmit={handleSave}>
              <div className="form-group">
                <label>Full Name</label>
                <input className="input-field" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} required />
              </div>
              <div className="form-row">
                <div className="form-group">
                  <label>Mobile Number</label>
                  <input className="input-field" value={form.phone} onChange={e => setForm({ ...form, phone: e.target.value })} />
                </div>
                <div className="form-group">
                  <label>Parent/Guardian Phone</label>
                  <input className="input-field" value={form.parentPhone} onChange={e => setForm({ ...form, parentPhone: e.target.value })} />
                </div>
              </div>
              <div className="form-group">
                <label>Boarding Point</label>
                <input className="input-field" value={form.boardingPoint} onChange={e => setForm({ ...form, boardingPoint: e.target.value })} />
              </div>
              <div className="form-group">
                <label>Home Address</label>
                <textarea className="input-field" rows={2} value={form.address} onChange={e => setForm({ ...form, address: e.target.value })} />
              </div>
              <button type="submit" className="btn btn-primary" disabled={saving}>
                {saving ? 'Updating...' : 'Save Profile Changes'}
              </button>
            </form>
          </div>

          <div className="card">
            <div className="card-header">
              <h3 className="card-title"><span>🔒</span> Update Password</h3>
            </div>
            <form onSubmit={handlePassword}>
              <div className="form-group">
                <label>Current Password</label>
                <input 
                  className="input-field" 
                  type="password" 
                  value={pwForm.currentPassword} 
                  onChange={e => setPwForm({ ...pwForm, currentPassword: e.target.value })} 
                  required 
                />
              </div>
              <div className="form-row">
                <div className="form-group">
                  <label>New Password</label>
                  <input 
                    className="input-field" 
                    type="password" 
                    value={pwForm.newPassword} 
                    onChange={e => setPwForm({ ...pwForm, newPassword: e.target.value })} 
                    required 
                    minLength={6} 
                  />
                </div>
                <div className="form-group">
                  <label>Confirm New Password</label>
                  <input 
                    className="input-field" 
                    type="password" 
                    value={pwForm.confirmPassword} 
                    onChange={e => setPwForm({ ...pwForm, confirmPassword: e.target.value })} 
                    required 
                  />
                </div>
              </div>
              <button type="submit" className="btn btn-outline" disabled={pwSaving}>
                {pwSaving ? 'Updating...' : 'Update Password'}
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}
